/**팝업게시판 리스트*/
SELECT A.* FROM (

	SELECT A.*
	FROM t_banner A
	WHERE 1=1


) A
ORDER BY IDX desc
limit #{firstRecordIndex},#{recordCountPerPage}

mapper.update:
/** 통합게시판 수정 */
UPDATE t_banner 
SET
	TITLE=#{title}
	,START_DTIME=#{startDtime}
	,END_DTIME=#{endDtime}
	,STATUS=#{status}
	,URL=#{url}
	,SORT=#{sort}
WHERE
	IDX=#{idx}

UPDATE t_banner 
SET
	FILE_IMG_NM=#{fileImgNm}
	,FILE_IMG_RENM=#{fileImgRenm}
WHERE
	IDX=#{idx}

UPDATE t_banner 
SET
	status=#{status}
WHERE
	IDX=#{idx}
